library(shiny)
library(dplyr)
library(readr)
library(matrixStats)
library(S7)
library(ggplot2)
library(bslib)

# ==============================================================================
# GLOBAL SETUP & PIPELINE CORE (Runs once when app boots)
# ==============================================================================

logit <- function(p) {
  if (max(p, na.rm = TRUE) > 1) { p <- p / 100 }
  p <- pmax(pmin(p, 0.9999), 0.0001)
  return(log(p / (1 - p)))
}

ln_plus_1 <- function(x) { return(log(1 + x)) }

data_path <- "usnewsmba26.csv"

if (!file.exists(data_path)) {
  stop(paste("File not found! Please check path:", data_path))
}

raw_data <- read_csv(data_path)

baseline_transformed <- raw_data %>%
  mutate(
    t_acceptance_rate = logit(acceptance_rate),
    t_er3mo           = logit(er3mo),
    t_er0mo           = logit(er0mo),
    t_GMAT            = ln_plus_1(GMAT),
    t_salbon          = ln_plus_1(salbon),
    t_peerscore       = peerscore,
    t_recruiterscore  = recruiterscore,
    t_GPA             = GPA
  )

market_scaling <- list(
  mean_acpt = mean(baseline_transformed$t_acceptance_rate, na.rm = TRUE),
  sd_acpt   = sd(baseline_transformed$t_acceptance_rate, na.rm = TRUE),
  mean_er3  = mean(baseline_transformed$t_er3mo, na.rm = TRUE),
  sd_er3    = sd(baseline_transformed$t_er3mo, na.rm = TRUE),
  mean_er0  = mean(baseline_transformed$t_er0mo, na.rm = TRUE),
  sd_er0    = sd(baseline_transformed$t_er0mo, na.rm = TRUE),
  mean_gmat = mean(baseline_transformed$t_GMAT, na.rm = TRUE),
  sd_gmat   = sd(baseline_transformed$t_GMAT, na.rm = TRUE),
  mean_sal  = mean(baseline_transformed$t_salbon, na.rm = TRUE),
  sd_sal    = sd(baseline_transformed$t_salbon, na.rm = TRUE),
  mean_peer = mean(baseline_transformed$t_peerscore, na.rm = TRUE),
  sd_peer   = sd(baseline_transformed$t_peerscore, na.rm = TRUE),
  mean_rec  = mean(baseline_transformed$t_recruiterscore, na.rm = TRUE),
  sd_rec    = sd(baseline_transformed$t_recruiterscore, na.rm = TRUE),
  mean_gpa  = mean(baseline_transformed$t_GPA, na.rm = TRUE),
  sd_gpa    = sd(baseline_transformed$t_GPA, na.rm = TRUE)
)

coefficients <- list(
  intercept       = 54.8689, 
  acceptance_rate = -1.25661635256423,
  er3mo           = 2.25747741106775,
  er0mo           = 2.25747741106775,
  GMAT            = 1.83362172093085,
  salbon          = 9.13672371296472,
  peerscore       = 4.91287979245853,
  recruiterscore  = 3.61503590578329,
  GPA             = 2.80023471272553
)

DEFAULTS <- list(
  salbon          = 122929,
  er3mo           = 0.708,
  er0mo           = 0.477,
  GMAT            = 465,
  GPA             = 3.30,
  acceptance_rate = 0.251,
  peerscore       = 3.2,
  recruiterscore  = 3.4
)

calculate_predictions <- function(df, coeffs) {
  df %>%
    mutate(
      predicted_score = coeffs$intercept +
        (z_acceptance_rate * coeffs$acceptance_rate) +
        (z_er3mo           * coeffs$er3mo) +
        (z_er0mo           * coeffs$er0mo) +
        (z_GMAT            * coeffs$GMAT) +
        (z_salbon          * coeffs$salbon) +
        (z_peerscore       * coeffs$peerscore) +
        (z_recruiterscore  * coeffs$recruiterscore) +
        (z_GPA             * coeffs$GPA)
    )
}

