    "))
  ),
  
  sidebar = sidebar(
    title = "Sensitivity Tuning Controls",
    
    actionButton("reset_btn", "Reset to Default Baseline", 
                 icon = icon("rotate-left"), 
                 class = "btn-outline-danger w-100 mb-1",
