# ==============================================================================
# SHINY APPLICATION SERVER LOGIC
# ==============================================================================
server <- function(input, output, session) {
  
  # --- 1. BI-DIRECTIONAL INPUT SYNCHRONIZATION LOGIC ---
  sync_pair <- function(num_id, slider_id) {
    observeEvent(input[[num_id]], {
      req(input[[num_id]])
      if (is.na(input[[slider_id]]) || input[[num_id]] != input[[slider_id]]) {
        updateSliderInput(session, slider_id, value = input[[num_id]])
      }
    }, ignoreInit = TRUE)
    
    observeEvent(input[[slider_id]], {
      req(input[[slider_id]])
      if (is.na(input[[num_id]]) || input[[slider_id]] != input[[num_id]]) {
        updateNumericInput(session, num_id, value = input[[slider_id]])
      }
    }, ignoreInit = TRUE)
  }
  
  sync_pair("num_salbon", "salbon")
  sync_pair("num_er3mo", "er3mo")
  sync_pair("num_er0mo", "er0mo")
  sync_pair("num_GMAT", "GMAT")
  sync_pair("num_GPA", "GPA")
  sync_pair("num_acceptance_rate", "acceptance_rate")
  sync_pair("num_peerscore", "peerscore")
  sync_pair("num_recruiterscore", "recruiterscore")
  
  # --- 2. GLOBAL RESET EVENT WATCHER ---
  observeEvent(input$reset_btn, {
    for (name in names(DEFAULTS)) {
      updateSliderInput(session, name, value = DEFAULTS[[name]])
      updateNumericInput(session, paste0("num_", name), value = DEFAULTS[[name]])
    }
  })
  
  # --- 3. CORE SIMULATION RECONSTRUCTION ENGINE ---
  simulation_results <- reactive({
    req(input$salbon, input$er3mo, input$er0mo, input$GMAT, input$GPA, input$acceptance_rate, input$peerscore, input$recruiterscore)
    
    modified_data <- raw_data %>%
      mutate(
        salbon          = ifelse(school == "George Washington University", input$salbon, salbon),
        er3mo           = ifelse(school == "George Washington University", input$er3mo, er3mo),
        er0mo           = ifelse(school == "George Washington University", input$er0mo, er0mo),
        GMAT            = ifelse(school == "George Washington University", input$GMAT, GMAT),
        GPA             = ifelse(school == "George Washington University", input$GPA, GPA),
        acceptance_rate = ifelse(school == "George Washington University", input$acceptance_rate, acceptance_rate),
        peerscore       = ifelse(school == "George Washington University", input$peerscore, peerscore),
        recruiterscore  = ifelse(school == "George Washington University", input$recruiterscore, recruiterscore)
      )
    
    processed_data <- modified_data %>%
      mutate(
        t_acceptance_rate = logit(acceptance_rate),
        t_er3mo           = logit(er3mo),
        t_er0mo           = logit(er0mo),
        t_GMAT            = ln_plus_1(GMAT),
        t_salbon          = ln_plus_1(salbon),
        t_peerscore       = peerscore,
        t_recruiterscore  = recruiterscore,
        t_GPA             = GPA
      ) %>%
      mutate(
        z_acceptance_rate = (t_acceptance_rate - market_scaling$mean_acpt) / market_scaling$sd_acpt,
        z_er3mo           = (t_er3mo - market_scaling$mean_er3) / market_scaling$sd_er3,
        z_er0mo           = (t_er0mo - market_scaling$mean_er0) / market_scaling$sd_er0,
        z_GMAT            = (t_GMAT - market_scaling$mean_gmat) / market_scaling$sd_gmat,
        z_salbon          = (t_salbon - market_scaling$mean_sal) / market_scaling$sd_sal,
        z_peerscore       = (t_peerscore - market_scaling$mean_peer) / market_scaling$sd_peer,
        z_recruiterscore  = (t_recruiterscore - market_scaling$mean_rec) / market_scaling$sd_rec,
        z_GPA             = (t_GPA - market_scaling$mean_gpa) / market_scaling$sd_gpa
      )
    
    base_predictions <- calculate_predictions(processed_data, coefficients)
    
    n_schools <- nrow(base_predictions)
    n_simulations <- 10000
    gwu_index <- which(base_predictions$school == "George Washington University")
    
    set.seed(120) 
    
    score_matrix        <- matrix(base_predictions$predicted_score, nrow = n_schools, ncol = n_simulations)
    raw_noise_matrix    <- matrix(rnorm(n_schools * n_simulations, 0, 1), nrow = n_schools, ncol = n_simulations)
    scale_matrix        <- matrix(base_predictions$noisescale, nrow = n_schools, ncol = n_simulations, byrow = FALSE)
    scaled_noise_matrix <- raw_noise_matrix * scale_matrix
    simulated_scores    <- score_matrix + scaled_noise_matrix
    
    rank_matrix <- (n_schools + 1) - colRanks(simulated_scores, ties.method = "random", preserveShape = TRUE)
    return(rank_matrix[gwu_index, ])
  })
  
  # --- 4. DATA RENDERERS ---
  output$mean_out <- renderText({ round(mean(simulation_results()), 2) })
  output$median_out <- renderText({ median(simulation_results()) })
  
  output$ci_out <- renderText({
    ranks <- simulation_results()
    paste0("[", quantile(ranks, 0.025), " - ", quantile(ranks, 0.975), "]")
  })
  
  output$rank_plot <- renderPlot({
    ranks <- simulation_results()
    mean_val <- mean(ranks)
    sim_plot_data <- data.frame(Rank = ranks)
    
    ggplot(sim_plot_data, aes(x = Rank)) +
      geom_histogram(binwidth = 1, fill = "#1c3b57", color = "white", alpha = 0.85) +
      geom_vline(aes(xintercept = mean_val), color = "#e74c3c", linetype = "dashed", size = 1.0) +
      theme_minimal(base_size = 10) + 
      theme(
        plot.margin = margin(2, 2, 2, 2, "mm"),
        axis.title.x = element_text(margin = margin(t = 4)),
        axis.title.y = element_text(margin = margin(r = 4))
      ) +
      labs(
        x = "Simulated U.S. News Rank Outcome",
        y = "Frequency / Count"
      ) +
      scale_x_continuous(breaks = seq(min(ranks) - 1, max(ranks) + 1, by = 2))
  })
}

shinyApp(ui = ui, server = server)
